out = []
for r in DATA:
    el = {
        "type": "node",
        "id": r["id"],
        "lat": r["lat"],
        "lon": r["lon"],
        "tags": {
            "amenity": "restaurant",
            "name": r["name"],
        }
    }
    if "cuisine" in r:
        el["tags"]["cuisine"] = r["cuisine"]
    if "addr" in r:
        el["tags"]["address"] = r["addr"]
    out.append(el)

result = {
    "version": 0.6,
    "generator": "Aura.ai OSM extract",
    "elements": out
}

target = os.path.join(os.path.dirname(__file__), "osm_nashville.json")
with open(target, "w") as f:
    json.dump(result, f, indent=2)

print(f"Written {len(out)} restaurants to {target}")
